// var — 函数作用域，泄漏
if (true) { var x = 1; }
console.log(x); // 1 ✅ 泄漏！

// let — 块级作用域，安全
if (true) { let y = 1; }
console.log(y); // ❌ ReferenceError

const name = "global";
function outer() {
  const name = "outer";
  function inner() {
    const name = "inner";
    console.log(name); // "inner"
  }
}

function createCounter() {
  let count = 0;        // 外层变量
  return () => ++count; // 返回的函数引用count
}
const counter = createCounter();
counter(); // 1
counter(); // 2 — count被闭包保持！

function createCounter(init = 0) {
  let count = init;
  return {
    increment: () => ++count,
    get: () => count
  };
}

function createMultiplier(factor) {
  return (n) => n * factor;
}
const double = createMultiplier(2);
double(5); // 10

function debounce(fn, ms) {
  let timer;
  return (...args) => {
    clearTimeout(timer);
    timer = setTimeout(() => fn(...args), ms);
  };
}

for (var i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 100);
}
// 输出: 3, 3, 3 — 共享同一个i！

for (let i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 100);
}
// 输出: 0, 1, 2 — 每次循环创建新作用域
